-- Summary
SELECT 'device_catalog_approval' as tbl, COUNT(*) FROM device_catalog_approval
UNION ALL
SELECT 'module_catalog_approval', COUNT(*) FROM module_catalog_approval;

SELECT a.code,
  COUNT(DISTINCT da.device_catalog_id) as devices,
  COUNT(DISTINCT ma.module_catalog_id) as modules
FROM approval a
LEFT JOIN device_catalog_approval da ON da.approval_id = a.id
LEFT JOIN module_catalog_approval ma ON ma.approval_id = a.id
GROUP BY a.code
ORDER BY a.code;

COMMIT;
